#pragma mark - 预热网络

// 通过轻量请求尽早触发系统网络权限弹窗或建立连接，避免首条真实消息被系统弹窗打断
- (void)warmUpNetwork:(void (^)(BOOL online))completion {
    // 使用常见的公共可达地址进行连通性探测，以触发权限或建立连接
    NSArray<NSString *> *testURLs = @[
        @"https://www.apple.com/library/test/success.html",
        @"https://www.apple.com",
        @"https://www.baidu.com",
        @"https://www.qq.com",
        @"https://www.microsoft.com"
    ];

    NSURLSessionConfiguration *config = [NSURLSessionConfiguration ephemeralSessionConfiguration];
    config.requestCachePolicy = NSURLRequestReloadIgnoringLocalCacheData;
    config.timeoutIntervalForRequest = 4.0;
    config.timeoutIntervalForResource = 6.0;
    if (@available(iOS 11.0, *)) {
        config.waitsForConnectivity = YES;
    }
    if (@available(iOS 13.0, *)) {
        config.allowsConstrainedNetworkAccess = YES; // 低数据模式下也尝试
        config.allowsExpensiveNetworkAccess = YES;   // 蜂窝等昂贵网络允许
    }
    NSURLSession *session = [NSURLSession sessionWithConfiguration:config];

    __block void (^probe)(NSInteger);
    probe = ^(NSInteger idx) {
        if (idx >= testURLs.count) {
            dispatch_async(dispatch_get_main_queue(), ^{ if (completion) completion(NO); });
            return;
        }
        NSString *uStr = testURLs[idx];
        NSURL *url = [NSURL URLWithString:uStr];
        if (!url) { probe(idx + 1); return; }
        NSMutableURLRequest *req = [NSMutableURLRequest requestWithURL:url cachePolicy:NSURLRequestReloadIgnoringLocalCacheData timeoutInterval:4.0];
        req.HTTPMethod = @"GET"; // HEAD 可能被部分站点拒绝，采用 GET 更通用
        NSURLSessionDataTask *task = [session dataTaskWithRequest:req completionHandler:^(NSData * _Nullable data, NSURLResponse * _Nullable response, NSError * _Nullable error) {
            if ([response isKindOfClass:[NSHTTPURLResponse class]]) {
                dispatch_async(dispatch_get_main_queue(), ^{ if (completion) completion(YES); });
            } else if (!error) {
                dispatch_async(dispatch_get_main_queue(), ^{ if (completion) completion(YES); });
            } else {
                probe(idx + 1);
            }
        }];
        [task resume];
    };

    probe(0);
}

