+ (BOOL)isBuiltInChatItem:(AIChatListItemModel *)item {
    if (item.chatId.length == 0) {
        return NO;
    }
    if ([item.chatId hasPrefix:@"ai_chat_default_"]) {
        return YES;
    }
    NSSet<NSString *> *legacyTitles = [NSSet setWithArray:@[@"Emotion", @"Outdoor sports", @"Music", @"Learn", @"Emosi", @"Olahraga luar ruangan", @"Musik"]];
    return [legacyTitles containsObject:item.title ?: @""];
}

+ (NSMutableArray<AIChatListItemModel *> *)loadCustomChatList {
    NSMutableArray<AIChatListItemModel *> *list = [NSMutableArray array];
    NSString *path = [self chatListFilePath];
    NSData *data = [NSData dataWithContentsOfFile:path];
    if (!data) {
        return list;
    }
    NSError *err = nil;
    id obj = [NSJSONSerialization JSONObjectWithData:data options:0 error:&err];
    if (err || ![obj isKindOfClass:[NSArray class]]) {
        return list;
    }
    for (NSDictionary *d in (NSArray *)obj) {
        if (![d isKindOfClass:[NSDictionary class]]) continue;
        AIChatListItemModel *m = [AIChatListItemModel fromDict:d];
        if ([self isBuiltInChatItem:m]) {
            continue;
        }
        [list addObject:m];
    }
    return list;
}

+ (void)saveCustomChatList:(NSArray<AIChatListItemModel *> *)list {
    NSMutableArray *arr = [NSMutableArray arrayWithCapacity:list.count];
    for (AIChatListItemModel *m in list) {
        if ([self isBuiltInChatItem:m]) {
            continue;
        }
        [arr addObject:[m toDict]];
    }
    NSError *err = nil;
    NSData *data = [NSJSONSerialization dataWithJSONObject:arr options:0 error:&err];
    if (!err && data) {
        [data writeToFile:[self chatListFilePath] atomically:YES];
    }
}

