    NSString *path = [self messagesFilePathForChatId:item.chatId];
    if ([[NSFileManager defaultManager] fileExistsAtPath:path]) {
        return;
    }
    NSMutableArray<AIChatListMessageModel *> *msgs = [NSMutableArray array];
    for (NSString *t in texts) {
        AIChatListMessageModel *m = [[AIChatListMessageModel alloc] initWithText:t time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO];
        [msgs addObject:m];
    }
    [self saveMessages:msgs forChatId:item.chatId];
}

