// 保证问候语固定在第一、第二条
+ (void)ensureGreetingsAtTop:(NSMutableArray<AIChatListMessageModel *> *)array {
    NSString *assistant = [self assistantDisplayName];
    NSString *greet1Text = [NSString stringWithFormat:@"你好! 我是 %@.", assistant];
    NSString *greet2Text = [NSString stringWithFormat:@"你好, %@!", assistant];

    NSIndexSet *toRemove = [array indexesOfObjectsPassingTest:^BOOL(AIChatListMessageModel * _Nonnull obj, NSUInteger idx, BOOL * _Nonnull stop) {
        BOOL isGreet1 = ([obj.text isEqualToString:greet1Text] && obj.type == AIChatListMessageTypeReceived);
        BOOL isGreet2 = ([obj.text isEqualToString:greet2Text] && obj.type == AIChatListMessageTypeSent);
        return isGreet1 || isGreet2;
    }];
    if (toRemove.count > 0) {
        [array removeObjectsAtIndexes:toRemove];
    }

    AIChatListMessageModel *message1 = [[AIChatListMessageModel alloc] initWithText:greet1Text time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO];
    AIChatListMessageModel *message2 = [[AIChatListMessageModel alloc] initWithText:greet2Text time:[NSDate date] type:AIChatListMessageTypeSent context:@"" Done:NO];

    [array insertObject:message2 atIndex:0];
    [array insertObject:message1 atIndex:0];
}

+ (NSMutableArray<AIChatListMessageModel *> *)messages {
    if (_messagesStore) {
        return _messagesStore;
    }
    _messagesStore = [NSMutableArray array];
    NSData *data = [NSData dataWithContentsOfFile:[self filePath]];
    if (data) {
        NSError *error = nil;
        id obj = [NSJSONSerialization JSONObjectWithData:data options:0 error:&error];
        if (!error && [obj isKindOfClass:[NSArray class]]) {
            for (NSDictionary *dict in (NSArray *)obj) {
                if ([dict isKindOfClass:[NSDictionary class]]) {
                    [_messagesStore addObject:[self messageFromDictionary:dict]];
                }
            }
        }
    }
    [self ensureGreetingsAtTop:_messagesStore];
    return _messagesStore;
}

+ (void)saveMessages {
    if (!_messagesStore) { return; }
    NSMutableArray *array = [NSMutableArray arrayWithCapacity:_messagesStore.count];
    for (AIChatListMessageModel *message in _messagesStore) {
        [array addObject:[self dictionaryFromMessage:message]];
    }
    NSError *error = nil;
    NSData *data = [NSJSONSerialization dataWithJSONObject:array options:0 error:&error];
    if (!error && data) {
        [data writeToFile:[self filePath] atomically:YES];
    }
}

